class TestFlattenEdgeCases:
    """Edge cases like empty lists, single elements, and unusual nesting."""

    def test_empty_list(self):
        assert flatten([]) == []

    def test_list_of_empty_lists(self):
        assert flatten([[], [], []]) == []

    def test_nested_empty_lists(self):
        assert flatten([[[[]]], []]) == []

    def test_single_element(self):
        assert flatten([42]) == [42]

    def test_single_nested_element(self):
        assert flatten([[42]]) == [42]

    def test_list_with_none(self):
        assert flatten([None, [None, [None]]]) == [None, None, None]

    def test_list_with_booleans(self):
        assert flatten([True, [False, [True]]]) == [True, False, True]

    def test_preserves_order(self):
        assert flatten([3, [1, [4, 1], 5], 9, [2, 6]]) == [3, 1, 4, 1, 5, 9, 2, 6]

